function sumArr(arr) {
  if (arr.length === 0) return 0;        // base
  return arr[0] + sumArr(arr.slice(1));  // récursif
}

// Inverser une chaîne
function reverse(s) {
  if (s.length <= 1) return s;
  return reverse(s.slice(1)) + s[0];
}

